const MANAGERS = [
  {name:"마틴레니",    start:"2014-09-16", end:"2016-06-15"},
  {name:"인창수(대행)",start:"2016-06-16", end:"2016-06-27"},
  {name:"박건하",      start:"2016-06-28", end:"2017-01-08"},
  {name:"김병수",      start:"2017-01-09", end:"2017-12-31"},
  {name:"인창수",      start:"2018-01-01", end:"2018-12-31"},
  {name:"김현수",      start:"2019-01-01", end:"2019-05-22"},
  {name:"우성용(대행)",start:"2019-05-23", end:"2019-11-27"},
  {name:"정정용",      start:"2019-11-28", end:"2022-12-31"},
  {name:"박충균",      start:"2023-01-01", end:"2023-12-31"},
  {name:"김도균",      start:"2024-01-01", end:"2099-12-31"},
];

function getManager(dateStr) {
  const d = parseDate(dateStr);
  for (const m of MANAGERS) {
    const s = parseDate(m.start), e = parseDate(m.end);
    if (s <= d && d <= e) return m.name;
  }
  return "미확인";
}

