// ─── 역대 감독 체제 ────────────────────────────────────────



function populateSchedule() {
  const sel = document.getElementById('inp-match');
  if(!sel) return;
  const today = new Date();
  today.setHours(0,0,0,0);
  sel.innerHTML = '<option value="">— 경기 선택 —</option>';
  let firstUpcoming = -1;
  SCHEDULE.forEach((s, i) => {
    const d = parseDate(s[2]);
    const wdKR = ['일','월','화','수','목','금','토'][d.getDay()];
    const venue = s[3]==='H' ? '홈' : '원정';
    const stadium = s[5] || '';
    const isPast = d < today;
    const roundStr = s[0] + 'R';
    const label = `${roundStr} · ${s[2]} (${wdKR}) · ${venue} vs ${s[4]} · ${stadium}`;
    sel.innerHTML += `<option value="${i}" ${isPast?'style="color:#4a5a7a"':''}>${isPast?'[완료] ':''}${label}</option>`;
    if(!isPast && firstUpcoming===-1) firstUpcoming = i;
  });
  if(firstUpcoming !== -1) {
    sel.value = firstUpcoming;
    onMatchSelect();
  }
}

function onMatchSelect() {
  const sel = document.getElementById('inp-match');
  const idx = sel.value;
  if(idx === '') {
    document.getElementById('match-info-preview').style.display='none';
    document.getElementById('inp-opponent').value = '';
    return;
  }
  const s = SCHEDULE[+idx];
  const d = parseDate(s[2]);
  const wdKR = ['일','월','화','수','목','금','토'][d.getDay()];
  const venue = s[3]==='H' ? '홈' : '원정';
  const stadium = s[5] || '';
  document.getElementById('inp-opponent').value = s[4];
  const preview = document.getElementById('match-info-preview');
  preview.style.display = 'block';
  preview.innerHTML = `<span style="color:var(--gold2);font-weight:700">${s[0]}R · vs ${s[4]}</span> &nbsp;|&nbsp; ${s[2]} (${wdKR}요일) &nbsp;|&nbsp; ${venue} &nbsp;|&nbsp; <span style="color:var(--gray)">${stadium}</span>`;
}

