// 페이지 로드 시 추가 목록 표시



function buildManagerTableRows(mgrStats) {
  var sorted = mgrStats.slice().sort(function(a,b){
    if(a.isCurrent) return -1;
    if(b.isCurrent) return 1;
    // 최신 취임일 순
    return b.start > a.start ? 1 : -1;
  });
  return sorted.map(function(m) {
    var rowClass = m.isCurrent ? 'current-season' : '';
    var fw = m.isCurrent ? 700 : 400;
    return '<tr class="' + rowClass + '">'
      + '<td style="font-weight:' + fw + '">' + m.name + (m.isCurrent ? ' ▶' : '') + '</td>'
      + '<td style="color:var(--gray);font-size:.72rem">' + m.start.slice(0,7) + ' ~ ' + (m.isCurrent ? '현재' : m.end.slice(0,7)) + '</td>'
      + '<td>' + m.games + '</td>'
      + '<td style="color:var(--green)">' + m.r.w + '</td>'
      + '<td style="color:var(--draw)">' + m.r.d + '</td>'
      + '<td style="color:var(--red)">' + m.r.l + '</td>'
      + '<td><strong>' + m.pts + '</strong> <span style="color:var(--gray);font-size:.7rem">(' + m.winRate + '%)</span></td>'
      + '<td style="color:var(--gray2)">' + m.gamesAll + '</td>'
      + '<td style="color:var(--green);opacity:.7">' + m.ra.w + '</td>'
      + '<td style="color:var(--draw);opacity:.7">' + m.ra.d + '</td>'
      + '<td style="color:var(--red);opacity:.7">' + m.ra.l + '</td>'
      + '<td style="opacity:.7">' + m.ptsAll + '</td>'
      + '</tr>';
  }).join('');
}

function renderHistoryTab() {
  var container = document.getElementById('history-container');
  if(!container || container.dataset.rendered) return;
  container.dataset.rendered = '1';

  // 검색/필터 UI
  var filterHtml = '<div style="display:flex;gap:10px;margin-bottom:16px;flex-wrap:wrap;align-items:center;">'
    + '<select id="hist-search" style="background:var(--navy3);border:1px solid var(--border);color:var(--white);padding:6px 10px;border-radius:6px;font-size:.78rem;min-width:130px;"><option value="">전체 상대팀</option><option value="FC서울">FC서울</option><option value="강원">강원</option><option value="경남">경남</option><option value="고려대">고려대</option><option value="고양">고양</option><option value="광주">광주</option><option value="김천">김천</option><option value="김포">김포</option><option value="대구">대구</option><option value="대전">대전</option><option value="대전코레일">대전코레일</option><option value="부산">부산</option><option value="부천">부천</option><option value="상주">상주</option><option value="선문대">선문대</option><option value="성균관대">성균관대</option><option value="성남">성남</option><option value="수원">수원</option><option value="수원FC">수원FC</option><option value="아산무궁화">아산무궁화</option><option value="안산">안산</option><option value="안산무궁화">안산무궁화</option><option value="안양">안양</option><option value="울산">울산</option><option value="인천">인천</option><option value="인천송월FC">인천송월FC</option><option value="전남">전남</option><option value="전북">전북</option><option value="제주">제주</option><option value="창원시청">창원시청</option><option value="천안">천안</option><option value="충남아산">충남아산</option><option value="충북청주">충북청주</option><option value="충주">충주</option><option value="파주">파주</option><option value="포천시민">포천시민</option><option value="호남대">호남대</option><option value="화성">화성</option></select>'
    + '<select id="hist-league" style="background:var(--navy3);border:1px solid var(--border);color:var(--white);padding:6px 10px;border-radius:6px;font-size:.78rem;">'
    + '<option value="">전체 대회</option><option value="K리그">K리그</option><option value="FA컵">FA컵</option><option value="PO">플레이오프</option>'
    + '</select>'
    + '<select id="hist-result" style="background:var(--navy3);border:1px solid var(--border);color:var(--white);padding:6px 10px;border-radius:6px;font-size:.78rem;">'
    + '<option value="">전체 결과</option><option value="W">승</option><option value="D">무</option><option value="L">패</option>'
    + '</select>'
    + '<select id="hist-venue" style="background:var(--navy3);border:1px solid var(--border);color:var(--white);padding:6px 10px;border-radius:6px;font-size:.78rem;">'
    + '<option value="">홈/원정</option><option value="H">홈</option><option value="A">원정</option>'
    + '</select>'
    + '<span id="hist-count" style="color:var(--gray);font-size:.75rem;margin-left:4px"></span>'
    + '</div>';

  // 테이블 헤더
  var tableHtml = '<div style="overflow-x:auto;"><table class="season-table" id="hist-table">'
    + '<thead><tr>'
    + '<th style="width:40px">No.</th>'
    + '<th style="width:55px">대회</th>'
    + '<th style="width:70px">날짜</th>'
    + '<th>상대</th>'
    + '<th style="width:45px">H/A</th>'
    + '<th style="width:55px">스코어</th>'
    + '<th style="width:35px">결과</th>'
    + '<th>특이사항</th>'
    + '</tr></thead>'
    + '<tbody id="hist-tbody"></tbody>'
    + '</table></div>';

  container.innerHTML = '<div class="card">'
    + '<div class="card-title">역대 경기 기록 <span style="color:var(--gray);font-size:.72rem;font-weight:400">총 436경기</span></div>'
    + filterHtml + tableHtml + '</div>';

  function buildRows(data) {
    var tbody = document.getElementById('hist-tbody');
    var count = document.getElementById('hist-count');
    tbody.innerHTML = '';
    count.textContent = data.length + '경기';
    data.forEach(function(m) {
      var no=m[0], season=m[1], league=m[2], date=m[3], venue=m[4], opp=m[5], res=m[6], gf=m[7], ga=m[8], note=m[9];
      var resColor = res==='W'?'var(--green)':res==='D'?'var(--draw)':'var(--red)';
      var resLabel = res==='W'?'승':res==='D'?'무':'패';
      var venueLabel = venue==='H'?'<span style="color:var(--gold2)">홈</span>':'<span style="color:var(--gray)">원정</span>';
      var leagueColor = league==='K리그'?'var(--blue)':league==='FA컵'?'var(--green)':'var(--gold)';
      var noteHtml = note ? '<span style="color:var(--gold2);font-size:.68rem;font-weight:700">★ '+note.replace(/\|/g,' · ')+'</span>' : '';
      var tr = document.createElement('tr');
      if(note) tr.style.background = 'rgba(212,175,55,0.06)';
      tr.innerHTML = '<td style="color:var(--gray);font-size:.72rem">'+no+'</td>'
        + '<td><span style="font-size:.65rem;color:'+leagueColor+';border:1px solid '+leagueColor+'33;padding:1px 4px;border-radius:3px">'+league+'</span></td>'
        + '<td style="font-size:.72rem;color:var(--gray)">'+date+'</td>'
        + '<td style="font-weight:500">'+opp+'</td>'
        + '<td style="text-align:center">'+venueLabel+'</td>'
        + '<td style="text-align:center;font-weight:700">'+gf+'-'+ga+'</td>'
        + '<td style="text-align:center;color:'+resColor+';font-weight:700">'+resLabel+'</td>'
        + '<td>'+noteHtml+'</td>';
      tbody.appendChild(tr);
    });
  }

  buildRows(MATCH_HISTORY);

  function applyFilter() {
    var search = document.getElementById('hist-search').value.toLowerCase();
    var league = document.getElementById('hist-league').value;
    var result = document.getElementById('hist-result').value;
    var venue  = document.getElementById('hist-venue').value;
    var filtered = MATCH_HISTORY.filter(function(m) {
      return (!search || m[5] === search)
        && (!league || m[2] === league)
        && (!result || m[6] === result)
        && (!venue  || m[4] === venue);
    });
    buildRows(filtered);
  }

  ['hist-search','hist-league','hist-result','hist-venue'].forEach(function(id) {
    var el = document.getElementById(id);
    el.addEventListener('input', applyFilter);
    el.addEventListener('change', applyFilter);
  });
}

window.addEventListener('load', () => {
  populateSchedule();
  const $ = id => document.getElementById(id);
  $('btn-run-report') && $('btn-run-report').addEventListener('click', runReport);
  $('inp-match')      && $('inp-match').addEventListener('change', onMatchSelect);
});

// ─── 요일 변환 (select value는 0=월~6=일, JS Date는 0=일~6=토) ─
function selectToJSWeekday(v) {
  // select: 0=월,1=화,2=수,3=목,4=금,5=토,6=일
  // JS:     0=일,1=월,2=화,3=수,4=목,5=금,6=토
  return [1,2,3,4,5,6,0][+v];
}

function runReport() {
  const opp = document.getElementById('inp-opponent').value.trim();
  if(!opp){ alert('상대팀을 입력해주세요'); return; }

  // 일정에서 자동 추출
  const matchIdx = document.getElementById('inp-match').value;
  let venue = 'H', nextDate = null, wdJS = 0;
  if(matchIdx !== '') {
    const s = SCHEDULE[+matchIdx];
    venue = s[3];
    nextDate = parseDate(s[2]);
    wdJS = nextDate.getDay(); // JS: 0=일
  }
  renderReport(opp, venue, nextDate, wdJS);
}

// 일정 선택 시 자동 반영 (onMatchSelect)